from agent import *from models.products import *import simplejsonXCAT = ['Brand', 'Australian Stocks', 'SIMs', 'Clearance']def run(context, session):    session.queue(Request('https://buymobile.com.au/', use='curl', force_charset='utf-8'), process_frontpage, dict())def process_frontpage(data, context, session):    cats1 = data.xpath('//ul[@class="main-nav"]/li')    for cat1 in cats1:        name1 = cat1.xpath('div/a/span/text()').string()        if name1 not in XCAT:            cats2 = cat1.xpath('.//div[contains(@class, "mega-sub-link")]')            for cat2 in cats2:                name2 = cat2.xpath("a/span/text()").string().replace('All ', '').replace('Other ', '')                url = cat2.xpath("a/@href").string()                if name2 not in XCAT:                    session.queue(Request(url, use='curl', force_charset='utf-8'), process_prodlist, dict(cat=name1+'|'+name2))def process_prodlist(data, context, session):    prods = data.xpath('//div[contains(@class, "product-grid-item")]')    for prod in prods:        name = prod.xpath('.//h5//text()').string()        prod_id = prod.xpath('.//h5//@href').string().split('/')[-1]        url = 'https://buymobile.com.au/products/' + prod_id        manufacturer = prod.xpath('.//div[@class="product-vendor"]/a/text()').string()        ssid = prod.xpath('.//span/@data-id').string()        revs_cnt = prod.xpath('.//span[@class="jdgm-prev-badge__text"][not(contains(., "No"))]/text()').string()        if revs_cnt:            revs_cnt = int(revs_cnt.split()[0])            if revs_cnt > 0:                session.queue(Request(url, use='curl', force_charset='utf-8'), process_product, dict(context, name=name, url=url, ssid=ssid, manufacturer=manufacturer))    next_url = data.xpath('//link[@rel="next"]/@href').string()    if next_url:        session.queue(Request(next_url, use='curl', force_charset='utf-8'), process_prodlist, dict(context))def process_product(data, context, session):    product = Product()    product.name = context['name']    product.url = context['url']    product.category = context['cat'].strip(' |')    product.manufacturer = context['manufacturer']    product.ssid = context['ssid']    info = data.xpath('//script[contains(., "productVariants=")]/text()').string()    if info:        info = info.split('productVariants=')[-1].split(';window')[0]        prod_json = simplejson.loads(info)[0]        mpn = prod_json.get('sku')        if mpn:            product.properties.append(ProductProperty(type='id.manufacturer', value=mpn))        ean = prod_json.get('barcode')        if ean:            product.properties.append(ProductProperty(type='id.ean', value=str(ean)))    if product.ssid:        revs_url = 'https://judge.me/reviews/reviews_for_widget?url=buymobilerapidco.myshopify.com&shop_domain=buymobilerapidco.myshopify.com&platform=shopify&page=1&per_page=10&product_id={}'.format(product.ssid)        session.do(Request(revs_url, use='curl', force_charset='utf-8', max_age=0), process_reviews, dict(product=product))    if product.reviews:        session.emit(product)def process_reviews(data, context, session):    product = context["product"]    json = simplejson.loads(data.content)    html = data.parse_fragment(json["html"])    revs = html.xpath("//div[@class='jdgm-rev jdgm-divider-top']")    for rev in revs:        review = Review()        review.title = rev.xpath(".//b[@class='jdgm-rev__title']//text()").string()        review.type = 'user'        review.url = product.url        review.ssid = rev.xpath(".//@data-review-id").string()        date = rev.xpath(".//span[@class='jdgm-rev__timestamp jdgm-spinner']/@data-content").string()        if date:            review.date = date.split(" ")[0]        author = rev.xpath(".//span[@class='jdgm-rev__author']/text()").string()        if author and author != 'null':            review.authors.append(Person(name=author, ssid=author))        grade_overall = rev.xpath(".//span/@data-score").string()        if grade_overall:            review.grades.append(Grade(type='overall', value=float(grade_overall), best=5.0))        is_verified = rev.xpath('@data-verified-buyer').string()        if is_verified == 'true':            review.add_property(type='is_verified_buyer', value=True)        hlp_yes = rev.xpath('@data-thumb-up-count').string()        if hlp_yes:            review.add_property(type='helpful_votes', value=int(hlp_yes))        hlp_no = rev.xpath('@data-thumb-down-count').string()        if hlp_no:            review.add_property(type='not_helpful_votes', value=int(hlp_no))        excerpt = rev.xpath(".//div[@class='jdgm-rev__body']//text()").string(multiple=True)        if excerpt:            review.properties.append(ReviewProperty(type='excerpt', value=excerpt))            product.reviews.append(review)    next_url = html.xpath('//a[@rel="next"]')    if next_url:        next_page = context.get("page", 1) + 1        revs_url = 'https://judge.me/reviews/reviews_for_widget?url=buymobilerapidco.myshopify.com&shop_domain=buymobilerapidco.myshopify.com&platform=shopify&page={}&per_page=10&product_id={}'.format(next_page, product.ssid)        session.do(Request(revs_url, use='curl', force_charset='utf-8', max_age=0), process_reviews, dict(product=product, page=next_page))